import React, { useMemo, useRef, useState } from "react";
import HourlyItem from "./HourlyItem";

function normPop(p) {
  if (p == null || Number.isNaN(Number(p))) return null;
  let x = Number(p);
  if (x > 1) x = x / 100;
  return Math.max(0, Math.min(1, x));
}

const iconUrl = (code) => `https://openweathermap.org/img/wn/${code}@2x.png`;

function guessIconCode(label, hour) {
  const s = String(label || "").toLowerCase();
  const day = hour >= 7 && hour < 19 ? "d" : "n";
  if (s.includes("thunder")) return `11${day}`;
  if (s.includes("snow") || s.includes("sleet") || s.includes("hail")) return `13${day}`;
  if (s.includes("rain") || s.includes("drizzle")) return `10${day}`;
  if (s.includes("fog") || s.includes("mist") || s.includes("haze") || s.includes("smoke")) return `50${day}`;
  if (s.includes("cloud")) return `03${day}`;
  return `01${day}`;
}

function safeWeatherLabel(w) {
  if (w == null) return "—";
  if (typeof w === "string" || typeof w === "number") return String(w);
  if (Array.isArray(w) && w.length) {
    const first = w[0];
    if (typeof first === "string") return first;
    if (first && typeof first === "object") return first.description || first.main || "—";
    return "—";
  }
  if (typeof w === "object") return w.description || w.main || "—";
  return String(w);
}

export default function Hourly({
  hourly = [],
  timezone = "local",
  unit = "metric",
  className = "",
}) {
  const listRef = useRef(null);
  const [page, setPage] = useState(0);
  const items = useMemo(() => (Array.isArray(hourly) ? hourly.slice(0, 24) : []), [hourly]);

  const fmtHour = (unixSec, idx) => {
    const ms = (typeof unixSec === "number" ? unixSec : Math.floor(Date.now() / 1000) + (idx + 1) * 3600) * 1000;
    const d = new Date(ms);
    const opts = { hour: "numeric" };
    if (timezone && timezone !== "local") opts.timeZone = timezone;
    const hourLabel = d.toLocaleTimeString([], opts);
    const hour24 = Number(
      d.toLocaleTimeString([], { hour: "2-digit", hour12: false, timeZone: opts.timeZone }).slice(0, 2)
    );
    return { hourLabel, hour24 };
  };

  const onScroll = () => {
    const el = listRef.current;
    if (!el) return;
    const w = el.clientWidth;
    setPage(Math.round(el.scrollLeft / Math.max(1, w * 0.8)));
  };

  return (
    <div className={`rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-3 ${className}`}>
      <div
        ref={listRef}
        onScroll={onScroll}
        className="flex gap-3 overflow-x-auto snap-x snap-mandatory scrollbar-none"
      >
        {items.length ? (
          items.map((h, i) => {
            const { hourLabel, hour24 } = fmtHour(h?.dt, i);
            const wx = h?.weather ?? h?.description ?? null;
            const label = safeWeatherLabel(wx);

            const iconFromArray = Array.isArray(h?.weather) ? h.weather[0]?.icon : null;
            const iconFromObj = !Array.isArray(h?.weather) && typeof h?.weather === "object" ? h.weather?.icon : null;
            const iconCode = iconFromArray || iconFromObj || guessIconCode(label, hour24);

            const temp = Math.round(Number(h?.temp ?? 0));
            const popPct = (() => {
              const x = normPop(h?.pop);
              return x == null ? null : Math.round(x * 100);
            })();

            const precip = typeof h?.precipitation === "number" ? h.precipitation : 0;

            return (
              <HourlyItem
                key={h?.dt ?? i}
                label={hourLabel}
                temp={temp}
                pop={popPct}
                icon={iconCode}
                desc={label}
                precip={precip}
                unit={unit}
                iconSrc={iconUrl(iconCode)}
              />
            );
          })
        ) : (
          <div className="opacity-70 text-sm text-white">No hourly data.</div>
        )}
      </div>

      {/* page dots on mobile */}
      <div className="flex justify-center gap-1 mt-3 md:hidden">
        {Array.from({ length: Math.max(1, Math.ceil(items.length / 4)) }).map((_, i) => (
          <span
            key={i}
            className={`h-2 w-2 rounded-full ${i === page ? "bg-purple-400" : "bg-white/30"}`}
          />
        ))}
      </div>
    </div>
  );
}
